/** 是否为通话类型（Video Call / Voice Call） */
export const isCallType = (type: RecordType): boolean =>
  type === RecordType.Video_Call || type === RecordType.Voice_Call;

/** 是否为美分显示类型 */
export const isCentsType = (type: RecordType): boolean =>
  type === RecordType.Message || type === RecordType.Texting_Pot || type === RecordType.Waiting_Reward;

/** PwaUserBalanceChangeType -> RecordType 映射表 */
export const CHANGE_TYPE_TO_RECORD_TYPE: Record<number, RecordType> = {
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_VIDEO_CALL]: RecordType.Video_Call,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_VOICE_CALL]: RecordType.Voice_Call,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_MESSAGE_TEXT]: RecordType.Texting_Pot,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_LIVE_STREAM]: RecordType.Live,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_DAILY_TASK]: RecordType.Task,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_ONBOARDING_TASK]: RecordType.Task,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_TUTORIAL_TASK]: RecordType.Task,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_SEND_GIFT]: RecordType.Gifts,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_WAITING_REWARD]: RecordType.Waiting_Reward,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_RECEIVE_GIFT]: RecordType.Receive_Gifts,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_INS_MESSAGE_TEXT]: RecordType.Ins_Messages,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_INS_FOLLOW_REWARD]: RecordType.Ins_Followers,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_MOCK_VIDEO]: RecordType.Video_Call,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_SPIN_WIN]: RecordType.Game,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_SPIN_COST]: RecordType.Game,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_CHAT_ORDER]: RecordType.Other,

  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_SPIN_NOT_ENOUGH_REWARD]: RecordType.Game,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_USER_VIDEO_TEST_REWARD]: RecordType.Other,
  [PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_USER_VIDEO_TEST_LOSS]: RecordType.Other,
};

/** 是否为通话类 BalanceChangeType（Video/Voice/MockVideo） */
export function isCallChangeType(type: number): boolean {
  return (
    type === PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_VIDEO_CALL ||
    type === PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_VOICE_CALL ||
    type === PwaUserBalanceChangeType.PWA_USER_BALANCE_CHANGE_TYPE_MOCK_VIDEO
  );
}

/** 将单条 API 余额变动记录转换为 RecordItem */
export function buildRecordItem(h: PwaUserBalanceChangeHistory, orders: CallOrderInfo[], dateKey: string): RecordItem {
  const changeTimeSec = h.changeTime ?? 0;
  const amount = parseFloat(h.changeBalance ?? "0") || 0;
  const changeType = h.type ?? 0;
  const recordType = CHANGE_TYPE_TO_RECORD_TYPE[changeType] ?? RecordType.Other;
  const isCall = isCallChangeType(changeType);
  const matchingOrders = isCall ? orders : [];

  const record: RecordItem = {
    id: `${dateKey}_${recordType}_${changeTimeSec}`,
    type: recordType,
    date: dateKey,
    amount,
    time: changeTimeSec,
    orders: isCall ? matchingOrders : undefined,
  };

  if (isCall && matchingOrders.length > 0) {
    const totalCallDuration = matchingOrders.reduce((s, o) => s + (o.callDuration ?? 0), 0);
    const totalFreeAmount = matchingOrders.reduce((s, o) => s + (parseFloat(o.freeAmount ?? "0") || 0), 0);
    record.duration = totalCallDuration;
    record.freeAmount = totalFreeAmount.toFixed(2);
  }

  return record;
}
