import { ReactNode } from "react";

interface CollapsibleProps {
  open: boolean;
  children: ReactNode;
  className?: string;
}

export default function Collapsible({ open, children, className = "" }: CollapsibleProps) {
  return (
    <div className={`collapsible ${className}`} data-open={open}>
      <div>{children}</div>
    </div>
  );
}
